{
  "name": "Choices for Care (CFC) Waiver",
  "eligibility": {
    "age": "65+ for seniors or 18+ for adults with physical disabilities[1][2][7]",
    "income_limits": "Up to 300% of SSI (e.g., $1,911/month for single individual in 2008; current amounts not specified in sources, consult ESD for 2026 figures). Applicant keeps some/all income for personal needs, uncovered medical expenses, spouse/dependent support. Spouse can have up to $2,644 (standard) or $3,948 (maximum) of applicant's income if excess shelter costs. Spend-down allowed to qualify[3][5][6]",
    "asset_limits": "$2,000 general resource limit for nursing home care eligibility (other limited exclusions). $10,000 for high/highest need medically needy single individuals owning/residing in own home selecting HCBS. Exempt: primary home (equity ≤$730,000 in 2025 if intent to return, spouse/minor child/disabled adult child living there), household furnishings/appliances, personal effects, vehicle. 60-month look-back rule penalizes asset transfers below fair market value[1][3][5][6]",
    "other_requirements": [
      "Vermont resident[1][2]",
      "Nursing Facility Level of Care (NFLOC): significant ADL assistance (transferring, eating, toileting, bed mobility), skilled nursing needs (wound care, tube feedings), cognitive/behavioral issues (e.g., dementia-related wandering, impaired judgment). Determined by in-person RN assessment[1][2]",
      "Both clinical (functional need via assessment) and financial eligibility required. Assigned to Highest Needs (entitled), High Needs (as resources permit), or Moderate Needs (limited, as resources permit) groups[1][2][3]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Home and Community-Based Services (HCBS) equivalent to nursing facility level, including assistance with ADLs/IADLs, skilled nursing, behavioral support. Specific services not itemized by hours/dollars; managed via global cap with priority for highest needs[1][2][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Contact Department of Vermont Health Access (DVHA), Economic Services Division (ESD) for financial eligibility; Department of Disabilities, Aging & Independent Living (DAIL) for functional assessment[3][4]",
      "No specific phone/website/form listed; start with eligibility screening including PASARR if appropriate[2][4]"
    ],
    "processing_time": "Not specified[null]",
    "waitlist": "High/Moderate Needs groups subject to state resources; Highest Needs entitled with no waitlist mentioned. Managed by professional judgment prioritizing unmet ADL/IADL/behavioral needs[2][3]",
    "forms": ["Application with assessment info; face-to-face review if needed[2]"],
    "documents": [
      "Financial info for past 5 years (income: pension, SS, VA, earnings; resources: property, vehicles, bank accounts, investments)",
      "Details on asset transfers/gifts in last 5 years[1][4]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Vermont residents only[1][2]",
    "regional_variations": "No regional differences specified; statewide with possible variations in wait times/resources by area not detailed[null]",
    "offices_or_providers": ["ESD (financial), DAIL (functional/clinical)[3][4]"]
  },
  "official_source": "https://www.medicaid.gov/Medicaid-CHIP-Program-Information/By-Topics/Waivers/1115/downloads/vt/vt-choices-for-care-ca.pdf[5]",
  "gotchas": [
    "60-month look-back penalizes asset transfers[1]",
    "Only Highest Needs guaranteed; High/Moderate depend on resources[2][3]",
    "Spouse income/assets handled specifically (not counted for applicant, but shelter allowances apply)[6]",
    "Dementia diagnosis alone insufficient; requires NFLOC assessment[1]",
    "Must meet both financial and clinical criteria[4]"
  ],
  "data_shape_notes": "Tiered by need level (Highest/High/Moderate) with entitlement only for Highest; income up to 300% SSI with spend-down; $10k asset allowance for community-living high/highest need singles; 60-month look-back applies[1][2][3][5]"
}

{
  "name": "3SquaresVT for Older Vermonters",
  "eligibility": {
    "age": 60,
    "income_limits": "Households where all members are 60+ or disabled and have no earned income from jobs or self-employment qualify via simplified process. General 3SquaresVT gross income limit is 185% FPL (household size table not specified in sources; check current FPL). Households with older adults (60+) or disabled members are exempt from gross income limit if over 185% FPL, but resources apply.[1][2][3]",
    "asset_limits": "No resource limits for most Vermonters. For elderly/disabled households over 185% FPL: $4,250 limit (includes savings, checking, investments, other assets; excludes primary home, vehicle, retirement/educational savings accounts like 401Ks, IRAs). Another source notes $3,500 limit for similar cases.[2][3]",
    "other_requirements": ["Households where everyone is 60+ or receiving disability benefits with no job/self-employment income for '3SquaresVT in a SNAP' simplified application and 3-year certification.[1]", "Categorical eligibility if receiving SSI, Reach Up (TANF), or Vermont EITC.[3]", "No general work requirements for elderly/disabled households.[2][3]"]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly food benefits via EBT card (usable at 600+ VT retailers, 40+ farmers' markets). For households where all are 65+ or SSI recipients: benefits issued as cash on EBT or direct bank deposit with verification. Exact amounts based on income/deductions (specific tables not in sources).[3][7]",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Online: dcf.vermont.gov/benefits/3SquaresVT/SNAP (simplified '3SquaresVT in a SNAP' application for 60+/disabled).[1]", "Phone: Not specified in sources; contact Economic Services Department (ESD).", "Other routes (mail, in-person) available via ESD offices statewide, not detailed."],
    "processing_time": "Not specified.",
    "waitlist": null,
    "forms": ["Simplified/shorter '3SquaresVT in a SNAP' application (vs. regular 3SquaresVT form) for qualifying elderly/disabled households; 3-year recertification without annual review.[1]"],
    "documents": ["Proof of income, disability (if applicable), resources if over limits, identity, residency. Specifics not detailed; prepare bank statements, SSI awards, etc.[2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": ["Administered statewide by Vermont Department for Children and Families (DCF) Economic Services Department (ESD). No regional provider differences noted.[1][2]"]
  },
  "official_source": "dcf.vermont.gov/benefits/3SquaresVT/SNAP",
  "gotchas": ["Must have no earned income from job/self-employment for simplified '3SquaresVT in a SNAP' process.[1]", "Asset limits ($3,500-$4,250) only apply if income over 185% FPL for elderly/disabled; many miss exemptions for home/vehicle/retirement accounts.[2][3]", "65+ or SSI households get cash benefits option, not just EBT food-only.[3]", "5-year wait for some noncitizens, with exceptions.[3]", "Traditional applications can lapse benefits; simplified version prevents this for qualifiers.[4]"],
  "data_shape_notes": "Simplified application and 3-year certification only for households all 60+/disabled with no earned income; asset test only for elderly/disabled over 185% FPL; cash benefits option for 65+/SSI."
}

